//=======================================BuildPackage======================================//
// Build the package from the NLS file
void GenericTabDialog::BuildPackage(int tabIndex, CATUnicodeString tabName, CATUnicodeString Package_NLSName,CATUnicodeString Package_NLSPath, bool isFeatureToCreate)
{
	if (!_pTabContainer)
		return;

	int index = 0;
	CATMsgCatalog msgCatalog;
	index = msgCatalog.LoadMsgCatalog(Package_NLSName.ConvertToChar(), Package_NLSPath.ConvertToChar());

	if (index == 0)
	{
		CATUnicodeString msg = "NLS file not available fo the below Package\n";
		msg.Append(Package_NLSName);
		msg.Append(" in the path ");
		msg.Append(Package_NLSPath);

		MRFGenericUtils::ShowErrorMessage(msg);
		return;

	}

	_isToCreateFeature = isFeatureToCreate;

	this->_tabIndex = tabIndex;

	_pTabPageGeneral = new CATDlgTabPage(_pTabContainer, tabName.ConvertToChar(), CATDlgGridLayout);
	_pTabPageGeneral->SetGridConstraints(0, tabIndex, 1, 1, CATGRID_4SIDES);
	
	if (tabIndex != 1)
		_pTabPageGeneral->SetSensitivity(CATDlgDisable);


	_pTabFrame = new CATDlgFrame(_pTabPageGeneral, (const char*)"Frame_Package", 0 | CATDlgFraNoTitle | CATDlgFraNoFrame | CATDlgGridLayout);
	_pTabFrame->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);



	if (_pTabFrame)
	{
		_pComboBoxParamFrame = new CATDlgFrame(_pTabFrame, (const char*)"Frame_Package", 0 | CATDlgFraNoTitle | CATDlgFraNoFrame | CATDlgGridLayout);
		_pComboBoxParamFrame->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);

		if (_pComboBoxParamFrame)
		{
			_pLabelUDFType = new CATDlgLabel(_pComboBoxParamFrame, (const char*)"UDFType", 0 | CATDlgLabLeft);
			_pLabelUDFType->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);

			_pComboUDFType = new CATDlgCombo(_pComboBoxParamFrame, (const char*)"Combo_UDF_Type", 0 | CATDlgCmbDropDown);
			_pComboUDFType->SetGridConstraints(0, 1, 1, 1, CATGRID_4SIDES);
			_pComboUDFType->SetVisibleTextWidth(30);
			this->SetComboBoxValuesReadFromNLS(_pComboUDFType, Package_NLSName, Package_NLSPath);

			_pPushButtonInstantiate = new CATDlgPushButton(_pComboBoxParamFrame, (const char*)"Instantiate", 0);
			_pPushButtonInstantiate->SetGridConstraints(0, 2, 1, 1, CATGRID_4SIDES);

			_pPushButtonImportExcelParam = new CATDlgPushButton(_pComboBoxParamFrame, (const char*)"Import_Parameters", 0);
			_pPushButtonImportExcelParam->SetGridConstraints(1, 0, 3, 1, CATGRID_4SIDES);


		}

		_pInputParamFrame = new CATDlgFrame(_pTabFrame, (const char*)"Input Parameters", 0 | CATDlgGridLayout);
		_pInputParamFrame->SetGridConstraints(1, 0, 10, 1, CATGRID_4SIDES);

		if (_pInputParamFrame)
		{
			_pMultiListInputParam = new CATDlgMultiList(_pInputParamFrame, (const char*)"MultiList Input Param", 0);
			_pMultiListInputParam->SetGridConstraints(0, 0, 10, 1, CATGRID_4SIDES);
			CATUnicodeString strHeader[3];
			strHeader[0] = "S.No";
			strHeader[1] = "Input Parameters Name";
			strHeader[2] = "Input Parameters Value";

			_pMultiListInputParam->SetColumnTitles(3, strHeader);
			_pMultiListInputParam->SetColumnTextWidth(0, 5);
			_pMultiListInputParam->SetColumnTextWidth(1, 15);
			_pMultiListInputParam->SetColumnTextWidth(2, 20);
			_pMultiListInputParam->SetVisibleLineCount(10);
			_pMultiListInputParam->SetVisibleColumnCount(3);
			_pMultiListInputParam->SetTitlesVisibility(TRUE);


			//_pSpinnerParamValue = new CATDlgSpinner(_pInputParamFrame, (const char*)"Spinner Selected Param", 0 | CATDlgSpnEntry);
			//_pSpinnerParamValue->SetGridConstraints(3, 16, 1, 1, CATGRID_4SIDES);
			//_pSpinnerParamValue->SetRange(-10000.0f, 10000.0f, 20000.0f);

			_paramEditFrameWithLabel = new CATDlgFrame(_pInputParamFrame, (const char*)"Selected_Parameter_Name", 0 | CATDlgFraNoTitle | CATDlgFraNoFrame | CATDlgGridLayout);
			_paramEditFrameWithLabel->SetGridConstraints(1, 0, 1, 1, CATGRID_4SIDES);

			_pLabelSelectedParamName = new CATDlgLabel(_paramEditFrameWithLabel, (const char*)"Selected_Parameter_Name", 0 | CATDlgLabLeft);
			_pLabelSelectedParamName->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);


			_pParamFrame = new CATDlgFrame(_paramEditFrameWithLabel, (const char*)"Param Frame", 0 | CATDlgFraNoTitle | CATDlgFraNoFrame |CATDlgGridLayout);
			_pParamFrame->SetGridConstraints(0, 1, 1, 1, CATGRID_4SIDES);

			_pLabelDummy = new CATDlgLabel(_pParamFrame, (const char*)"Selected_Parameter_Name", 0 | CATDlgLabLeft);
			_pLabelDummy->SetGridConstraints(0,1, 1, 1, CATGRID_4SIDES);
			_pLabelDummy->SetVisibility(CATDlgHide);

		}

		_pCalculatedParmFrame = new CATDlgFrame(_pTabFrame, (const char*)"Calculated Parameters", 0 | CATDlgGridLayout);
		_pCalculatedParmFrame->SetGridConstraints(2, 0, 1, 1, CATGRID_4SIDES);

		if (_pCalculatedParmFrame)
		{
			_pMultiListCalculatedParam = new CATDlgMultiList(_pCalculatedParmFrame, (const char*)"MultiList Calculated Param", 0);
			_pMultiListCalculatedParam->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);
			CATUnicodeString strHeaderCalculated[3];
			strHeaderCalculated[0] = "S.No";
			strHeaderCalculated[1] = "Calculated Parameters Name";
			strHeaderCalculated[2] = "Calculated Parameters Value";

			_pMultiListCalculatedParam->SetColumnTitles(3, strHeaderCalculated);
			_pMultiListCalculatedParam->SetColumnTextWidth(0, 5);
			_pMultiListCalculatedParam->SetColumnTextWidth(1, 15);
			_pMultiListCalculatedParam->SetColumnTextWidth(2, 20);
			_pMultiListCalculatedParam->SetVisibleLineCount(10);
			_pMultiListCalculatedParam->SetVisibleColumnCount(3);
			_pMultiListCalculatedParam->SetTitlesVisibility(TRUE);

		}
		
		//_pFeatureFrame = new CATDlgFrame(_pTabFrame, (const char*)"Frame_Package", 0 | CATDlgFraNoTitle | CATDlgFraNoFrame | CATDlgGridLayout);
		//_pFeatureFrame->SetGridConstraints(5, 0, 10, 1, CATGRID_4SIDES);

		if (isFeatureToCreate == TRUE)
		{
			_pPushButtonCreateFeature = new CATDlgPushButton(_pTabFrame, (const char*)"CreateFeature", 0);
			_pPushButtonCreateFeature->SetGridConstraints(3, 0, 1, 1, CATGRID_4SIDES);
		}
	}

}

//====================ActivateTabPage====================//
void GenericTabDialog::ActivateTabPage(bool isToActivate)
{
	if (isToActivate)
		this->_pTabPageGeneral->SetSensitivity(CATDlgEnable);
	else
		this->_pTabPageGeneral->SetSensitivity(CATDlgDisable);
}
//=========================================================//
void GenericTabDialog::ClearSelectWidgets()
{
	_pComboUDFType->ClearSelect();
	_pMultiListInputParam->ClearSelect();
	_pMultiListCalculatedParam->ClearSelect();

}

//==========================SetComboBoxValuesReadFromNLS==============================================//
// This function helps to read the udf name info from the nlsname passed to it. Then put it under the combo box index to display it to the user.
void GenericTabDialog::SetComboBoxValuesReadFromNLS(CATDlgCombo *pComboBox, CATUnicodeString NLSFileName,CATUnicodeString NLSFilePath)
{

	if (!pComboBox)
		return;

	int index = 0;
	CATMsgCatalog msgCatalog;
	index = msgCatalog.LoadMsgCatalog(NLSFileName.ConvertToChar(), NLSFilePath.ConvertToChar());

	if (index == 0)
	{
		CATUnicodeString msg = "NLS file not available fo the below Package\n";
		msg.Append(NLSFileName);
		msg.Append(" in the path ");
		msg.Append(NLSFilePath);

		MRFGenericUtils::ShowErrorMessage(msg);
		return;

	}

	CATUnicodeString  profileCountAsStr;
	int UDFCount = 0;
	CATString NLSFileNameLoc = NLSFileName, udfCountName = NLSFileNameLoc + ".UDFCount";

	profileCountAsStr = (msgCatalog.GetCatalogMsg(udfCountName)).BuildMessage();
	profileCountAsStr.ConvertToNum(&UDFCount, "%d");

	CATUnicodeString UDFNameListLines[100], udfName;
	bool atleatOneProfileFound = false;

	int UDFFound_Count = 0;
	for (int i = 1; i <= UDFCount; i++)
	{
		CATString NLSFileNameLocal = NLSFileName;

		CATString profileName = NLSFileNameLocal + ".UDF.";

		CATUnicodeString CountAsStr;
		CountAsStr.BuildFromNum(i);
		profileName.Append(CountAsStr.ConvertToChar());
		profileName.Append(".Name");

		udfName = (msgCatalog.GetCatalogMsg(profileName)).BuildMessage();
		if (!udfName.Compare(""))
		{
			UDFNameListLines[i - 1] = udfName;
			atleatOneProfileFound = true;
			UDFFound_Count++;
		}
	}

	/*for (int j = 0; j < profileCount; j++)
	{
		CATString sKey;
		CATUnicodeString usText;
		sprintf(bufferName_key, "MRFTWIMarkingCmd.UDFName.Profile_%d", j);
		sKey = bufferName_key;
		if (0 != _pMRFTWIMarkingDlg->GetResourceValueFromKey(sKey, usText))
		{
			UDFNameListLines[j] = usText;
			atleatOneProfileFound = true;
		}
	}*/

	if (atleatOneProfileFound)
		pComboBox->SetLine(UDFNameListLines, UDFFound_Count);
}
